import{_ as t,o as e,c as r,ag as l}from"./chunks/framework.CNG7EpJN.js";const p=JSON.parse('{"title":"メニュー管理","description":"","frontmatter":{"title":"メニュー管理"},"headers":[],"relativePath":"tenant/04-menu.md","filePath":"tenant/04-menu.md"}'),i={name:"tenant/04-menu.md"};function d(o,a,n,h,s,c){return e(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="_4-メニュー管理" tabindex="-1">4. メニュー管理 <a class="header-anchor" href="#_4-メニュー管理" aria-label="Permalink to &quot;4. メニュー管理&quot;">​</a></h1><p>メニュー管理では、カテゴリ、商品、価格、表示順、売り切れ、オプション、多言語表示を設定します。お客様のセルフオーダー画面、ハンディPOS、KDSに反映される重要な設定です。</p><h2 id="基本の流れ" tabindex="-1">基本の流れ <a class="header-anchor" href="#基本の流れ" aria-label="Permalink to &quot;基本の流れ&quot;">​</a></h2><ol><li>カテゴリを作成します。</li><li>商品を登録します。</li><li>価格、税区分、説明文、画像、表示順を設定します。</li><li>必要に応じてオプションを設定します。</li><li>セルフオーダー画面で表示を確認します。</li><li>テスト注文を行い、KDSと会計まで確認します。</li></ol><h2 id="カテゴリ管理" tabindex="-1">カテゴリ管理 <a class="header-anchor" href="#カテゴリ管理" aria-label="Permalink to &quot;カテゴリ管理&quot;">​</a></h2><p>カテゴリは「定食」「一品料理」「ドリンク」など、お客様が商品を探しやすい単位で作成してください。表示順を整えると、セルフオーダー画面でも見やすくなります。</p><h2 id="商品登録" tabindex="-1">商品登録 <a class="header-anchor" href="#商品登録" aria-label="Permalink to &quot;商品登録&quot;">​</a></h2><p>商品名、価格、説明文、画像、販売状態を登録します。写真や説明文は注文率に影響するため、実際の提供内容とずれないようにしてください。</p><h2 id="売り切れ設定" tabindex="-1">売り切れ設定 <a class="header-anchor" href="#売り切れ設定" aria-label="Permalink to &quot;売り切れ設定&quot;">​</a></h2><p>一時的に販売できない商品は、売り切れに設定します。売り切れにすると、お客様画面で注文できない状態になります。営業再開時には解除を忘れないようにしてください。</p><h2 id="オプション管理" tabindex="-1">オプション管理 <a class="header-anchor" href="#オプション管理" aria-label="Permalink to &quot;オプション管理&quot;">​</a></h2><p>トッピング、サイズ、辛さ、麺量などをオプションとして設定できます。追加料金がある場合は、会計金額に反映されることをテスト注文で確認してください。</p><h2 id="csv入出力" tabindex="-1">CSV入出力 <a class="header-anchor" href="#csv入出力" aria-label="Permalink to &quot;CSV入出力&quot;">​</a></h2><p>メニュー点数が多い場合は、CSVで一括登録・更新できます。取り込み前に、文字化け、価格、カテゴリ名、販売状態を確認してください。</p><h2 id="多言語表示" tabindex="-1">多言語表示 <a class="header-anchor" href="#多言語表示" aria-label="Permalink to &quot;多言語表示&quot;">​</a></h2><p>多言語設定を利用すると、外国語メニューを表示できます。自動翻訳後は、店舗で実際の表現を確認し、不自然な訳があれば調整してください。</p><h2 id="困ったとき" tabindex="-1">困ったとき <a class="header-anchor" href="#困ったとき" aria-label="Permalink to &quot;困ったとき&quot;">​</a></h2><table tabindex="0"><thead><tr><th>症状</th><th>対処</th></tr></thead><tbody><tr><td>商品が表示されない</td><td>カテゴリ、販売状態、店舗表示設定を確認してください。</td></tr><tr><td>価格が違う</td><td>商品価格とオプション価格を確認してください。</td></tr><tr><td>売り切れが戻らない</td><td>売り切れ設定を解除し、画面を再読み込みしてください。</td></tr><tr><td>CSVが取り込めない</td><td>文字コード、必須項目、価格の形式を確認してください。</td></tr></tbody></table>',18)])])}const _=t(i,[["render",d]]);export{p as __pageData,_ as default};
